  1→import { createContext, useContext, useReducer } from 'react';
  2→import { SKETCH_TOOLS, DEFAULT_SKETCH_ZOOM } from '../domain/defaults';
  3→
  4→const SketchEditorContext = createContext(null);
  5→
  6→function sketchEditorReducer(state, action) {
  7→  switch (action.type) {
  8→    case 'SET_TOOL':
  9→      return {
 10→        ...state,
 11→        activeTool: action.tool,
 12→        toolState: {},
 13→        selectedId: null,
 14→        selectedType: null,
 15→      };
 16→
 17→    case 'SELECT_OBJECT':
 18→      return {
 19→        ...state,
 20→        selectedId: action.id,
 21→        selectedType: action.objectType,
 22→      };
 23→
 24→    case 'DESELECT':
 25→      return {
 26→        ...state,
 27→        selectedId: null,
 28→        selectedType: null,
 29→      };
 30→
 31→    case 'UPDATE_TOOL_STATE':
 32→      return {
 33→        ...state,
 34→        toolState: { ...state.toolState, ...action.payload },
 35→      };
 36→
 37→    case 'SET_VIEWPORT':
 38→      return {
 39→        ...state,
 40→        viewport: { ...action.viewport },
 41→      };
 42→
 43→    case 'PAN':
 44→      return {
 45→        ...state,
 46→        viewport: {
 47→          ...state.viewport,
 48→          panX: state.viewport.panX + action.dx,
 49→          panY: state.viewport.panY + action.dy,
 50→        },
 51→      };
 52→
 53→    case 'ZOOM': {
 54→      const { zoom, panX, panY } = action;
 55→      return {
 56→        ...state,
 57→        viewport: { zoom, panX, panY },
 58→      };
 59→    }
 60→
 61→    case 'SET_VIEW':
 62→      return {
 63→        ...state,
 64→        activeView: action.view,
 65→      };
 66→
 67→    case 'SET_ACTIVE_ASSEMBLY':
 68→      return {
 69→        ...state,
 70→        activeAssemblyId: action.assemblyId,
 71→      };
 72→
 73→    case 'TOGGLE_GRID':
 74→      return { ...state, showGrid: !state.showGrid };
 75→
 76→    case 'TOGGLE_SNAP':
 77→      return { ...state, snapEnabled: !state.snapEnabled };
 78→
 79→    case 'SET_STATUS_MESSAGE':
 80→      return { ...state, statusMessage: action.message };
 81→
 82→    case 'CLEAR_STATUS_MESSAGE':
 83→      if (!state.statusMessage) return state;
 84→      return { ...state, statusMessage: null };
 85→
 86→    case 'DISMISS_EMPTY_STATE':
 87→      return { ...state, emptyStateDismissed: true };
 88→
 89→    default:
 90→      return state;
 91→  }
 92→}
 93→
 94→export function createInitialSketchEditorState() {
 95→  return {
 96→    activeTool: SKETCH_TOOLS.SELECT,
 97→    selectedId: null,
 98→    selectedType: null,
 99→    toolState: {},
100→    viewport: { panX: 400, panY: 300, zoom: DEFAULT_SKETCH_ZOOM },
101→    activeView: 'top',
102→    activeAssemblyId: null,
103→    showGrid: true,
104→    snapEnabled: true,
105→    statusMessage: null,
106→    emptyStateDismissed: false,
107→  };
108→}
109→
110→export function SketchEditorProvider({ children }) {
111→  const [state, dispatch] = useReducer(
112→    sketchEditorReducer,
113→    null,
114→    createInitialSketchEditorState
115→  );
116→
117→  return (
118→    <SketchEditorContext.Provider value={{ state, dispatch }}>
119→      {children}
120→    </SketchEditorContext.Provider>
121→  );
122→}
123→
124→export function useSketchEditor() {
125→  const ctx = useContext(SketchEditorContext);
126→  if (!ctx) throw new Error('useSketchEditor must be used within SketchEditorProvider');
127→  return { ...ctx.state, dispatch: ctx.dispatch };
128→}
