 1→import { lazy, Suspense } from 'react';
 2→import { createBrowserRouter, RouterProvider } from 'react-router-dom';
 3→
 4→const HomePage = lazy(() => import('./pages/HomePage'));
 5→const PlaygroundPage = lazy(() => import('./pages/PlaygroundPage'));
 6→const FloorplanWorkspace = lazy(() => import('./modules/floorplan'));
 7→const SketchWorkspace = lazy(() => import('./modules/sketch'));
