136→  const tool = useEditorTool({
137→    activeTool,
138→    dispatch,
139→    editorDispatch,
140→    project,
141→    getFloor,
142→    activeFloorId,
143→    roofSystem,
144→    trussSystems: floorTrussSystems,
145→    modelTarget,
146→    viewport,
147→    snapEnabled,
148→    selectedId,
149→    selectedType,
150→    toolState,
151→    viewMode,
152→    activePhaseId,
153→  });
154→
155→  const getModelPos = useCallback((e) => {
156→    const rect = svgRef.current.getBoundingClientRect();
157→    return screenToModel(e.clientX, e.clientY, viewport, rect);
158→  }, [viewport]);
