178→    if (isPanning.current) {
179→      const dx = e.clientX - lastPanPos.current.x;
180→      const dy = e.clientY - lastPanPos.current.y;
181→      editorDispatch({ type: 'PAN', dx, dy });
182→      lastPanPos.current = { x: e.clientX, y: e.clientY };
183→      return;
184→    }
185→
186→    const modelPos = getModelPos(e);
187→    cursorPosRef.current = modelPos;
188→    setCursorPos(modelPos);
189→    if (modelTarget === 'floor' && pastePreview?.active) {
190→      updatePastePreview(modelPos);
191→      return;
192→    }
193→    tool.onMouseMove(modelPos, e);
194→  }, [getModelPos, modelTarget, pastePreview, tool, updatePastePreview, editorDispatch]);
195→
196→  const handleMouseUp = useCallback((e) => {
197→    if (isPanning.current) {
198→      isPanning.current = false;
199→      return;
200→    }
201→    if (modelTarget === 'floor' && pastePreview?.active) return;
202→    const modelPos = getModelPos(e);
203→    tool.onMouseUp(modelPos, e);
204→  }, [getModelPos, modelTarget, pastePreview, tool]);
