117→function FloorplanInner({ isPlayground }) {
118→  const { project, isDirty, dispatch } = useProject();
119→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
120→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
121→  const availablePhaseIds = useMemo(() => (project.phases || []).map((p) => p.id), [project.phases]);
122→  const initialActiveFloorId = getDefaultActiveFloorId(project);
123→  const [showLoadModal, setShowLoadModal] = useState(false);
124→  const [showNewProjectModal, setShowNewProjectModal] = useState(false);
125→  const [savedProjects, setSavedProjects] = useState([]);
126→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
127→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
128→  const [projectFileHandle, setProjectFileHandle] = useState(null);
129→  const importInputRef = useRef(null);
130→
131→  useAutosave(project, isDirty && !isPlayground, dispatch);
132→
133→  // beforeunload warning
134→  useEffect(() => {
135→    const handler = (e) => {
136→      if (isDirty) {
137→        e.preventDefault();
138→        e.returnValue = '';
139→      }
140→    };
141→    window.addEventListener('beforeunload', handler);
142→    return () => window.removeEventListener('beforeunload', handler);
143→  }, [isDirty]);
144→
145→  const handleNew = useCallback(() => {
146→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
147→    setShowNewProjectModal(true);
148→  }, [isDirty]);
149→
150→  const handleCreateProject = useCallback(({ name }) => {
151→    const newProject = createProject(name);
152→    setProjectFileHandle(null);
153→    dispatch({ type: 'PROJECT_NEW', project: newProject });
154→    setShowNewProjectModal(false);
155→  }, [dispatch]);
156→
157→  const handleSave = useCallback(async () => {
158→    try {
159→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
160→      setProjectFileHandle(fileHandle);
161→      try {
162→        await saveProject(project);
163→      } catch {
164→        // Browser draft sync is secondary to file save.
165→      }
166→      dispatch({ type: 'MARK_SAVED' });
167→    } catch (err) {
168→      if (isFilePickerAbortError(err)) return;
169→      alert('Failed to save project file: ' + err.message);
170→    }
171→  }, [project, projectFileHandle, dispatch]);
172→
173→  // Ctrl+S save
174→  useEffect(() => {
175→    const handler = (e) => {
176→      if (isTypingTarget(e.target)) return;
177→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
178→        e.preventDefault();
179→        handleSave();
180→      }
181→    };
182→    window.addEventListener('keydown', handler);
183→    return () => window.removeEventListener('keydown', handler);
184→  }, [handleSave]);
185→
186→  const handleLoadClick = useCallback(async () => {
187→    setSavedProjects(await listProjects());
188→    setShowLoadModal(true);
189→  }, []);
190→
191→  const handleOpenProjectFile = useCallback(async () => {
192→    if (typeof window.showOpenFilePicker !== 'function') {
193→      importInputRef.current?.click();
194→      return;
195→    }
196→
197→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
198→      return;
199→    }
200→
201→    try {
202→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
203→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
204→      setProjectFileHandle(fileHandle);
205→      setShowLoadModal(false);
206→    } catch (err) {
207→      if (isFilePickerAbortError(err)) return;
208→      alert('Failed to import project file: ' + err.message);
209→    }
210→  }, [isDirty, dispatch]);
211→
212→  const handleImportFile = useCallback(async (e) => {
213→    const file = e.target.files?.[0] || null;
214→    e.target.value = '';
215→    if (!file) return;
216→
217→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
218→      return;
219→    }
220→
221→    try {
222→      const { project: loaded, savedAt } = await importProjectFile(file);
223→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
224→      setProjectFileHandle(null);
225→      setShowLoadModal(false);
226→    } catch (err) {
227→      alert('Failed to import project file: ' + err.message);
228→    }
229→  }, [isDirty, dispatch]);
230→
231→  const handleLoad = useCallback(async (id) => {
232→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
233→    try {
234→      const { project: loaded, savedAt } = await loadProject(id);
235→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
236→      setProjectFileHandle(null);
237→      setShowLoadModal(false);
238→    } catch (err) {
239→      alert('Failed to load project: ' + err.message);
240→    }
241→  }, [isDirty, dispatch]);
242→
243→  const handleDelete = useCallback(async (id, name) => {
244→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
245→    if (!confirmed) return;
246→
247→    try {
248→      await deleteProject(id);
249→      setSavedProjects(projects => projects.filter(project => project.id !== id));
250→    } catch (err) {
251→      alert('Failed to delete project: ' + err.message);
252→    }
253→  }, []);
254→
255→  return (
256→    <EditorProvider
257→      initialActiveFloorId={initialActiveFloorId}
258→      availableFloorIds={availableFloorIds}
259→      availablePhaseIds={availablePhaseIds}
260→    >
261→      <input
262→        ref={importInputRef}
263→        type="file"
264→        accept=".json,application/json"
265→        onChange={handleImportFile}
266→        style={{ display: 'none' }}
267→      />
268→
269→      <EditorShell
270→        project={project}
271→        handleNew={handleNew}
272→        handleSave={handleSave}
273→        handleLoadClick={handleLoadClick}
274→        isSidebarCollapsed={isSidebarCollapsed}
275→        isPropertiesCollapsed={isPropertiesCollapsed}
276→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
277→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
278→      />
279→
280→      {showNewProjectModal && (
281→        <NewProjectModal
282→          onConfirm={handleCreateProject}
283→          onClose={() => setShowNewProjectModal(false)}
284→        />
285→      )}
286→
287→      {showLoadModal && (
288→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
289→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
290→            <div className={modalStyles.modalCard}>
291→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
292→                <span className={modalStyles.modalCardTitle}>Project File</span>
293→                <span className={modalStyles.modalCardDesc}>
294→                  Open a JSON file previously saved to your computer.
295→                </span>
296→              </div>
297→              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
298→                Open Project File
299→              </button>
300→            </div>
301→
302→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
303→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
304→                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
305→                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
306→                  Stored only in this browser on this machine.
307→                </span>
308→              </div>
309→              {savedProjects.length === 0 ? (
310→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
311→                  No browser drafts found.
312→                </p>
313→              ) : (
314→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
315→                  {savedProjects.map(p => (
316→                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
317→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
318→                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
319→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
320→                          {new Date(p.savedAt).toLocaleDateString()}
321→                        </span>
322→                      </div>
323→                      <div style={{ display: 'flex', gap: '8px' }}>
324→                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
325→                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
326→                      </div>
327→                    </div>
328→                  ))}
329→                </div>
330→              )}
331→            </div>
332→          </div>
333→          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
334→            Cancel
335→          </button>
336→        </Modal>
337→      )}
338→    </EditorProvider>
339→  );
340→}
