 14→export function createPartPlaceHandler({ dispatch, editorDispatch, activeView, activeAssemblyId, partType, selectedId, project, snapEnabled }) {
 15→  const needsParent = partType === 'cutout' || partType === 'hole';
 16→
 17→  return {
 18→    onMouseDown(modelPos, e, toolState) {
 19→      if (e.button !== 0) return;
 20→
 21→      if (needsParent) {
 22→        const parentPart = selectedId ? project.parts.find((p) => p.id === selectedId) : null;
 23→        if (!parentPart || parentPart.type !== 'panel') {
 24→          editorDispatch({
 25→            type: 'SET_STATUS_MESSAGE',
 26→            message: `Select a panel first to place a ${partType}.`,
 27→          });
 28→          return;
 29→        }
 30→      }
 31→
 32→      const pos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;
 33→
 34→      editorDispatch({
 35→        type: 'UPDATE_TOOL_STATE',
 36→        payload: {
 37→          drawing: true,
 38→          startPos: { x: pos.x, y: pos.y },
 39→          currentPos: { x: pos.x, y: pos.y },
 40→        },
 41→      });
 42→    },
 43→
 44→    onMouseMove(modelPos, e, toolState) {
 45→      if (!toolState.drawing) return;
 46→
 47→      editorDispatch({
 48→        type: 'UPDATE_TOOL_STATE',
 49→        payload: {
 50→          currentPos: { x: modelPos.x, y: modelPos.y },
 51→        },
 52→      });
 53→    },
 54→
 55→    onMouseUp(modelPos, e, toolState) {
 56→      if (!toolState.drawing || !toolState.startPos) return;
 57→
 58→      const endPos = snapEnabled ? snapPoint(modelPos, SKETCH_GRID_MINOR) : modelPos;
 59→
 60→      const x = Math.min(toolState.startPos.x, endPos.x);
 61→      const y = Math.min(toolState.startPos.y, endPos.y);
 62→      const svgW = Math.abs(endPos.x - toolState.startPos.x);
 63→      const svgH = Math.abs(endPos.y - toolState.startPos.y);
 64→
 65→      const minSize = 10; // mm
 66→      if (svgW > minSize && svgH > minSize) {
 67→        const position = viewToModelPosition(x, y, activeView);
 68→        const extents = viewToModelExtents(svgW, svgH, activeView, partType);
 69→
 70→        const factory = partFactories[partType];
 71→        if (!factory) return;
 72→
 73→        const overrides = {
 74→          position,
 75→          ...extents,
 76→        };
 77→
 78→        if (needsParent) {
 79→          overrides.parentId = selectedId;
 80→        }
 81→
 82→        const part = factory(overrides);
 83→
 84→        dispatch({ type: 'PART_ADD', part });
 85→
 86→        if (activeAssemblyId) {
 87→          dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
 88→        }
 89→
 90→        editorDispatch({
 91→          type: 'SET_STATUS_MESSAGE',
 92→          message: `${partType}: ${Math.round(svgW)} x ${Math.round(svgH)} mm`,
 93→        });
 94→      }
 95→
 96→      editorDispatch({
 97→        type: 'UPDATE_TOOL_STATE',
 98→        payload: {
 99→          drawing: false,
100→          startPos: null,
101→          currentPos: null,
102→        },
103→      });
104→    },
105→
106→    onKeyDown(e) {
107→      if (e.key === 'Escape') {
108→        editorDispatch({
109→          type: 'UPDATE_TOOL_STATE',
110→          payload: {
111→            drawing: false,
112→            startPos: null,
113→            currentPos: null,
114→          },
115→        });
116→      }
117→    },
118→
119→    getCursor(toolState) {
120→      return 'crosshair';
121→    },
122→  };
123→}
