 10→function NumberInput({ label, value, onChange, suffix = 'mm', step = 1, readOnly = false }) {
 11→  return (
 12→    <label className={styles.field}>
 13→      <span className={styles.fieldLabel}>{label}</span>
 14→      <div className={styles.fieldInput}>
 15→        <input
 16→          type="number"
 17→          value={Math.round(value)}
 18→          step={step}
 19→          readOnly={readOnly}
 20→          onChange={(e) => {
 21→            const v = parseFloat(e.target.value);
 22→            if (!isNaN(v)) onChange(v);
 23→          }}
 24→          onBlur={(e) => {
 25→            if (readOnly) return;
 26→            const v = parseFloat(e.target.value);
 27→            if (!isNaN(v)) {
 28→              const clamped = clampDimension(v);
 29→              if (clamped !== v) onChange(clamped);
 30→            }
 31→          }}
 32→          className={styles.numberInput}
 33→        />
 34→        {suffix && <span className={styles.suffix}>{suffix}</span>}
