  1→import { buildFloorPreviewObjects } from './objectBuilders';
  2→import { buildRoofPreviewObjects } from '@/geometry/roof3dGeometry';
  3→import { getDefaultActiveFloorId, getFloorElevation, getFloorStackBounds, getOrderedFloors } from '@/domain/floorModels';
  4→import { buildTrussPreviewObjects } from '@/geometry/trussGeometry';
  5→
  6→function mergeBounds(current, next) {
  7→  if (!next) return current;
  8→  if (!current) return { ...next };
  9→
 10→  return {
 11→    minX: Math.min(current.minX, next.minX),
 12→    maxX: Math.max(current.maxX, next.maxX),
 13→    minY: Math.min(current.minY, next.minY),
 14→    maxY: Math.max(current.maxY, next.maxY),
 15→    minElevation: Math.min(current.minElevation, next.minElevation),
 16→    maxElevation: Math.max(current.maxElevation, next.maxElevation),
 17→  };
 18→}
 19→
 20→function boundsFromObjects(objects = []) {
 21→  return objects.reduce((accumulator, objectDescriptor) => (
 22→    mergeBounds(accumulator, objectDescriptor.bounds)
 23→  ), null);
 24→}
 25→
 26→function createFallbackBounds(stackBounds, activeFloor) {
 27→  const level = stackBounds?.minElevation ?? getFloorElevation(activeFloor);
 28→  const top = stackBounds?.maxElevation ?? (level + 3000);
 29→  return {
 30→    minX: -1500,
 31→    maxX: 1500,
 32→    minY: -1500,
 33→    maxY: 1500,
 34→    minElevation: level,
 35→    maxElevation: top,
 36→  };
 37→}
 38→
 39→function createNavigationTarget(bounds, fallbackBounds) {
 40→  const source = bounds || fallbackBounds;
 41→  return {
 42→    x: (source.minX + source.maxX) / 2,
 43→    z: (source.minY + source.maxY) / 2,
 44→  };
 45→}
 46→
 47→export function buildPreviewScene(project, options = {}) {
 48→  const floors = getOrderedFloors(project);
 49→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
 50→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
 51→  const topFloor = floors[floors.length - 1] || null;
 52→  const stackBounds = getFloorStackBounds(floors);
 53→  const resolvedVisibleFloorIds = options.visibleFloorIds || floors.map((floor) => floor.id);
 54→  const visibleFloorIds = new Set(resolvedVisibleFloorIds);
 55→
 56→  const floorDescriptors = floors.map((floor) => {
 57→    const trussObjects = (project?.trussSystems || [])
 58→      .filter((trussSystem) => trussSystem.floorId === floor.id)
 59→      .flatMap((trussSystem) => buildTrussPreviewObjects(trussSystem));
 60→    const objects = [...buildFloorPreviewObjects(floor), ...trussObjects];
 61→    return {
 62→      floorId: floor.id,
 63→      name: floor.name,
 64→      elevation: getFloorElevation(floor),
 65→      visible: visibleFloorIds.has(floor.id),
 66→      objects,
 67→      bounds: boundsFromObjects(objects),
 68→    };
 69→  });
 70→
 71→  if (project?.roofSystem) {
 72→    const roofObjects = buildRoofPreviewObjects(project.roofSystem)
 73→      .map((descriptor) => ({
 74→        ...descriptor,
 75→        metadata: {
 76→          ...(descriptor.metadata || {}),
 77→          floorId: topFloor?.id || activeFloorId,
 78→        },
 79→      }));
 80→
 81→    floorDescriptors.push({
 82→      floorId: project.roofSystem.id,
 83→      name: project.roofSystem.name || 'Roof',
 84→      elevation: project.roofSystem.baseElevation ?? stackBounds.maxElevation,
 85→      visible: !options.visibleFloorIds || (topFloor ? visibleFloorIds.has(topFloor.id) : true),
 86→      objects: roofObjects,
 87→      bounds: boundsFromObjects(roofObjects),
 88→    });
 89→  }
 90→
 91→  const visibleObjects = floorDescriptors
 92→    .filter((floor) => floor.visible)
 93→    .flatMap((floor) => floor.objects);
 94→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(stackBounds, activeFloor);
 95→  const floorsWithNavigationTargets = floorDescriptors.map((floor) => ({
 96→    ...floor,
 97→    navigationTarget: createNavigationTarget(floor.bounds, bounds),
 98→  }));
 99→
100→  return {
101→    activeFloorId,
102→    visibleFloorIds: [...visibleFloorIds],
103→    floors: floorsWithNavigationTargets,
104→    roofLayerId: project?.roofSystem?.id || null,
105→    bounds,
106→    defaultTarget: {
107→      x: (bounds.minX + bounds.maxX) / 2,
108→      y: (bounds.minElevation + bounds.maxElevation) / 2,
109→      z: (bounds.minY + bounds.maxY) / 2,
110→    },
111→    groundLevel: stackBounds.minElevation,
112→    hasVisibleObjects: visibleObjects.length > 0,
113→  };
114→}
