file.content:
.layout {
  display: grid;
  grid-template-rows: var(--toolbar-height) 1fr;
  grid-template-columns:
    var(--layout-sidebar-width, var(--sidebar-width))
    1fr
    var(--layout-properties-width, var(--properties-width));
  grid-template-areas:
    "toolbar toolbar toolbar"
    "sidebar canvas properties";
  height: 100%;
  width: 100%;
}

.toolbar {
  grid-area: toolbar;
  position: relative;
  z-index: 10;
}

.sidebar {
  grid-area: sidebar;
  min-height: 0;
  overflow-y: auto;
}

.canvas {
  grid-area: canvas;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  box-shadow: inset 1px 0 3px rgba(0, 0, 0, 0.04), inset -1px 0 3px rgba(0, 0, 0, 0.04);
}

.properties {
  grid-area: properties;
  min-height: 0;
  overflow-y: auto;
}

.modelWorkspace {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(300px, 28vw);
  width: 100%;
  height: 100%;
  min-width: 0;
  min-height: 0;
}

.primaryCanvas {
  min-width: 0;
  min-height: 0;
}

.preview {
  display: flex;
  min-width: 0;
  min-height: 0;
  height: 100%;
  overflow: hidden;
}

.previewFallback {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  min-height: 0;
  border-left: 1px solid var(--color-border);
  background: var(--color-panel-bg);
  color: var(--color-text-secondary);
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  position: relative;
  overflow: hidden;
}

.previewFallback::after {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
  animation: shimmer 1.5s infinite;
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.panelHidden {
  width: 0;
  overflow: hidden;
  padding: 0;
  border: none;
  transition: width var(--duration-layout) var(--ease-in-out-soft),
              padding var(--duration-layout) var(--ease-in-out-soft);
}

.workspaceMaximized {
  grid-template-columns: 1fr;
}

.previewHidden {
  display: none;
}

.primaryCanvasHidden {
  display: none;
}

@media (max-width: 1200px) {
  .modelWorkspace {
    grid-template-columns: minmax(0, 1fr);
    grid-template-rows: minmax(0, 1fr) 280px;
  }

  .previewFallback {
    border-left: none;
    border-top: 1px solid var(--color-border);
  }
}

@media (max-width: 1024px) {
  .layout {
    grid-template-columns: 0px 1fr 0px;
  }
  .sidebar, .properties {
    position: fixed;
    top: var(--toolbar-height);
    bottom: 0;
    z-index: 20;
    transition: transform var(--duration-layout) var(--ease-out);
    box-shadow: var(--shadow-floating);
    width: var(--sidebar-width);
    background: var(--color-panel-bg);
  }
  .sidebar {
    left: 0;
    transform: translateX(-100%);
  }
  .properties {
    right: 0;
    left: auto;
    width: var(--properties-width);
    transform: translateX(100%);
  }
  .sidebarVisible {
    transform: translateX(0);
  }
  .propertiesVisible {
    transform: translateX(0);
  }
  .panelHidden {
    width: auto;
  }
}

