  6→import { getViewLabel, viewToModelPosition } from '../domain/viewProjection';
  7→import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
  8→import { createPartPlaceHandler } from '../editor/handlers/partPlaceHandler';
