 16→function screenToModel(screenX, screenY, viewport, svgRect) {
 17→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 18→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 19→  return { x, y };
 20→}
