 22→function useSketchTool() {
 23→  const { dispatch: sketchDispatch, project } = useSketch();
 24→  const {
 25→    activeTool, viewport, snapEnabled, selectedId, selectedType,
 26→    toolState, activeView, activeAssemblyId, dispatch: editorDispatch,
 27→  } = useSketchEditor();
 28→
 29→  const ctx = {
 30→    dispatch: sketchDispatch,
 31→    editorDispatch,
 32→    project,
 33→    activeView,
 34→    activeAssemblyId,
 35→    viewport,
 36→    snapEnabled,
 37→    selectedId,
 38→    selectedType,
 39→  };
 40→
 41→  switch (activeTool) {
 42→    case 'panel':
 43→    case 'leg':
 44→    case 'frame':
 45→    case 'cutout':
 46→    case 'hole':
 47→      return createPartPlaceHandler({ ...ctx, partType: activeTool });
 48→    case 'dimension':
 49→      return createDimensionHandler(ctx);
 50→    case 'select':
 51→    default:
 52→      return createSketchSelectHandler(ctx);
 53→  }
 54→}
