247→export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [], availablePhaseIds = [] }) {
248→  const [state, dispatch] = useReducer(
249→    editorReducer,
250→    initialActiveFloorId,
251→    createInitialEditorState
252→  );
253→
254→  useEffect(() => {
255→    if (!availableFloorIds.length) {
256→      if (state.activeFloorId !== null) {
257→        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
258→      }
259→      return;
260→    }
261→
262→    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
263→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
264→    }
265→  }, [availableFloorIds, state.activeFloorId]);
266→
267→  useEffect(() => {
268→    if (state.activePhaseId && !availablePhaseIds.includes(state.activePhaseId)) {
269→      dispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
270→      dispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
271→    }
272→  }, [availablePhaseIds, state.activePhaseId]);
273→
274→  return (
275→    <EditorContext.Provider value={{ state, dispatch }}>
276→      {children}
277→    </EditorContext.Provider>
278→  );
279→}
