 85→function trussSupportLabel(floor, beamId) {
 86→  const beam = (floor?.beams || []).find((entry) => entry.id === beamId) || null;
 87→  if (!beam || !floor) return '—';
 88→  return getBeamDisplayLabel(beam, floor.columns || []);
