 91→function findObjectInFloor(floor, selectedType, selectedId) {
 92→  switch (selectedType) {
 93→    case 'wall':
 94→      return floor.walls?.find((wall) => wall.id === selectedId) || null;
 95→    case 'beam':
 96→      return (floor.beams || []).find((beam) => beam.id === selectedId) || null;
 97→    case 'column':
 98→      return (floor.columns || []).find((column) => column.id === selectedId) || null;
 99→    case 'slab':
100→      return (floor.slabs || []).find((slab) => slab.id === selectedId) || null;
101→    case 'stair':
102→      return (floor.stairs || []).find((stair) => stair.id === selectedId) || null;
103→    case 'landing':
104→      return (floor.landings || []).find((landing) => landing.id === selectedId) || null;
105→    case 'door':
106→      return floor.doors?.find((door) => door.id === selectedId) || null;
107→    case 'window':
108→      return floor.windows?.find((windowItem) => windowItem.id === selectedId) || null;
109→    case 'fixture':
110→      return (floor.fixtures || []).find((fixture) => fixture.id === selectedId) || null;
111→    case 'railing':
112→      return (floor.railings || []).find((r) => r.id === selectedId) || null;
113→    default:
114→      return null;
115→  }
116→}
